# Equivalente pedagógico a zip(..., strict=True) — Py 3.10+
def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError(f"desalineado: {len(a)} vs {len(b)}")
    return list(zip(a, b))

try:
    zip_strict(ids, regiones)
except ValueError as e:
    print("zip strict →", type(e).__name__ + ":", e)

