ids = ["C001", "C002", "C003"]
regiones = ["Lima", "Cusco", "Arequipa"]

def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError("desalineado")
    return zip(a, b)

for i, (rid, reg) in enumerate(zip_strict(ids, regiones), start=1):
    print(f"fila {i}: {rid} @ {reg}")
mal = ["Lima", "Cusco"]
try:
    list(zip_strict(ids, mal))
except ValueError:
    print("desalineado detectado")

